const monthlyTrends = $('Monthly Listing Trends').all().map(i => i.json);
const provinceTrends = $('Province Trends').all().map(i => i.json);
const leadTrends = $('Lead & Conversion Trends').all().map(i => i.json);

const currentMonth = monthlyTrends[0] || {};
const prevMonth = monthlyTrends[1] || {};

const fmt = (n) => 'R ' + Number(n).toLocaleString('en-ZA', { maximumFractionDigits: 0 });
const pct = (curr, prev) => {
  if (!prev || prev == 0) return 'N/A';
  const change = ((curr - prev) / prev * 100).toFixed(1);
  return change > 0 ? `+${change}%` : `${change}%`;
};

const reportPeriod = new Date();
reportPeriod.setMonth(reportPeriod.getMonth() - 1);
const reportMonthName = reportPeriod.toLocaleDateString('en-ZA', { month: 'long', year: 'numeric' });

const emailHtml = `
<!DOCTYPE html>
<html>
<head>
<style>
body{font-family:'Helvetica Neue',sans-serif;color:#333;margin:0;background:#f0f4f0;}
.container{max-width:750px;margin:0 auto;background:white;}
.header{background:linear-gradient(135deg,#1a472a,#40916c);color:white;padding:40px;text-align:center;}
.header h1{margin:0;font-size:26px;letter-spacing:1px;}
.header .period{opacity:0.85;margin-top:6px;font-size:15px;}
.section{padding:30px 35px;border-bottom:1px solid #eee;}
.section h2{color:#1a472a;font-size:17px;text-transform:uppercase;letter-spacing:0.5px;margin:0 0 20px;}
.kpi-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;}
.kpi{background:#f0f7f0;border-radius:8px;padding:16px;text-align:center;}
.kpi .value{font-size:24px;font-weight:900;color:#1a472a;}
.kpi .label{font-size:11px;color:#666;text-transform:uppercase;margin-top:4px;}
.kpi .change{font-size:12px;margin-top:4px;}
.up{color:#27ae60;} .down{color:#e74c3c;}
table{width:100%;border-collapse:collapse;font-size:13px;}
th{background:#f0f7f0;color:#1a472a;padding:10px;text-align:left;font-size:12px;text-transform:uppercase;}
td{padding:10px;border-bottom:1px solid #f0f0f0;}
tr:hover{background:#fafafa;}
.footer{background:#1a472a;color:rgba(255,255,255,0.7);padding:25px;text-align:center;font-size:12px;}
</style></head>
<body><div class="container">

<div class="header">
  <h1>PuraEstate Monthly Analytics Report</h1>
  <div class="period">${reportMonthName}</div>
</div>

<div class="section">
  <h2>Key Performance Indicators</h2>
  <div class="kpi-grid">
    <div class="kpi">
      <div class="value">${Number(currentMonth.total_listings || 0).toLocaleString()}</div>
      <div class="label">Total Listings</div>
      <div class="change ${Number(currentMonth.total_listings) >= Number(prevMonth.total_listings) ? 'up' : 'down'}">
        ${pct(currentMonth.total_listings, prevMonth.total_listings)} vs prev month
      </div>
    </div>
    <div class="kpi">
      <div class="value">${fmt(currentMonth.avg_price || 0)}</div>
      <div class="label">Avg Price</div>
      <div class="change ${Number(currentMonth.avg_price) >= Number(prevMonth.avg_price) ? 'up' : 'down'}">
        ${pct(currentMonth.avg_price, prevMonth.avg_price)} vs prev month
      </div>
    </div>
    <div class="kpi">
      <div class="value">${fmt(currentMonth.median_price || 0)}</div>
      <div class="label">Median Price</div>
      <div class="change">&nbsp;</div>
    </div>
    <div class="kpi">
      <div class="value">${currentMonth.provinces || 0}</div>
      <div class="label">Provinces</div>
      <div class="change">&nbsp;</div>
    </div>
  </div>
</div>

<div class="section">
  <h2>Province Breakdown</h2>
  <table>
    <tr><th>Province</th><th>This Month</th><th>Prev Month</th><th>Change</th><th>Avg Price</th></tr>
    ${provinceTrends.map(p => {
      const change = Number(p.last_month) - Number(p.prev_month);
      const changeStr = change > 0 ? `<span class="up">+${change}</span>` : `<span class="down">${change}</span>`;
      return `<tr><td>${p.province}</td><td>${p.last_month}</td><td>${p.prev_month}</td><td>${changeStr}</td><td>${fmt(p.last_month_avg_price)}</td></tr>`;
    }).join('')}
  </table>
</div>

<div class="section">
  <h2>12-Month Listing Trend</h2>
  <table>
    <tr><th>Month</th><th>Listings</th><th>Avg Price</th><th>Houses</th><th>Apts</th></tr>
    ${monthlyTrends.slice(0, 12).map(m => `
    <tr><td>${m.month}</td><td>${m.total_listings}</td><td>${fmt(m.avg_price)}</td><td>${m.houses}</td><td>${m.apartments}</td></tr>`).join('')}
  </table>
</div>

${leadTrends.length > 0 ? `
<div class="section">
  <h2>Lead Performance</h2>
  <table>
    <tr><th>Month</th><th>New Leads</th><th>Conversions</th><th>Lost</th><th>Rate</th></tr>
    ${leadTrends.slice(0, 6).map(l => `
    <tr><td>${l.month}</td><td>${l.new_leads}</td><td>${l.conversions}</td><td>${l.lost}</td><td>${l.conversion_rate}%</td></tr>`).join('')}
  </table>
</div>` : ''}

<div class="footer">PuraEstate Intelligence Platform | Confidential - Internal Use Only</div>
</div></body></html>`;

return [{
  json: {
    report_period: reportMonthName,
    email_html: emailHtml,
    subject: `PuraEstate Monthly Analytics Report - ${reportMonthName}`,
    total_listings: currentMonth.total_listings,
    avg_price: currentMonth.avg_price,
    provinces: currentMonth.provinces
  }
}];

